const input = $input.first().json;
if (typeof input.draft_text !== 'string' || input.draft_text.trim() === '') {
  throw new Error('F-08: draft_text must be a non-empty string');
}
if (typeof input.content_type !== 'string' || !input.content_type) {
  throw new Error('F-08: content_type is required');
}
if (typeof input.feature_tag !== 'string' || !input.feature_tag) {
  throw new Error('F-08: feature_tag is required');
}
return [{ json: input }];

const input = $('Aggregation Boundary Input').item.json;
const rosterRows = $('Fetch Roster').all();

const text = String(input.draft_text || '');
const violations = [];

// MED-01: normalize — NFKD decompose then strip non-ASCII handles diacritics
const normalize = s => String(s).normalize('NFKD').replace(/[^\x00-\x7F]/g, '').toLowerCase();
const textNorm = normalize(text);

// MED-01: word-boundary helper (no length gate)
const hasWordBoundary = (haystack, needle) => {
  let idx = 0;
  while ((idx = haystack.indexOf(needle, idx)) !== -1) {
    const pre  = idx === 0 || !/[a-z0-9]/.test(haystack[idx - 1]);
    const post = idx + needle.length >= haystack.length || !/[a-z0-9]/.test(haystack[idx + needle.length]);
    if (pre && post) return true;
    idx++;
  }
  return false;
};

// Check roster member names
for (const row of rosterRows) {
  const name = normalize(row.json.name || '');
  if (!name.trim()) continue;
  const parts = name.split(/\s+/).filter(p => p.length > 0);
  for (const part of parts) {
    if (hasWordBoundary(textNorm, part)) {
      violations.push('Individual name detected: [REDACTED]'); // MED-03: no name in log
      break;
    }
  }
}

// Check Discord snowflake IDs
const ids = rosterRows.map(r => String(r.json.discord_id || ''));
// MED-02: also check digit-only version to catch formatted IDs
const digitsOnly = text.replace(/\D/g, '');
const snowflakes = textNorm.match(/\b\d{17,19}\b/g) || [];
for (const id of ids) {
  if (!id) continue;
  if (snowflakes.includes(id) || (id.length >= 17 && digitsOnly.includes(id))) {
    violations.push('Discord ID detected: [REDACTED]'); // MED-03
    break;
  }
}

// Per-individual metric patterns
const metricPatterns = [
  [/\b\d+\s*commits?\b/i, 'commit count'],
  [/\b\d+\s*(hours?|hrs?)\s*(logged|tracked|worked)/i, 'individual hours'],
  [/logged\s+\d+\s*(hours?|hrs?)/i, 'individual hours (logged)'],
  [/\b(assigned to|done by|completed by|written by|handled by)\s+\w+/i, 'attribution phrase'],
  [/\b(he|she|they)\s+(committed|pushed|closed|opened|wrote|fixed|reviewed|built)\b/i, 'individual pronoun'],
];

for (const [re, label] of metricPatterns) {
  if (re.test(text)) {
    violations.push('Pattern matched: ' + label);
  }
}

return [{ json: {
  clean: violations.length === 0,
  violations,
  draft_text: input.draft_text,
  content_type: input.content_type,
  feature_tag: input.feature_tag
} }];

const audit = $input.first().json;

// HIGH-02: SC-11 — Refuse to send PII to a public LLM endpoint
const lmUrl = String($env.LLM_BASE_URL || '');
const host = lmUrl.replace(/^https?:\/\//, '').split(/[/:?#]/)[0];
const isPrivate =
  host === 'localhost' ||
  /^127\./.test(host) ||
  /^10\./.test(host) ||
  /^192\.168\./.test(host) ||
  /^172\.(1[6-9]|2[0-9]|3[01])\./.test(host) ||
  /^\[?::1\]?$/.test(host) ||
  /^\[?fe80:/i.test(host) ||
  !host.includes('.');  // Docker service name (e.g. 'ollama')
if (!isPrivate) {
  throw new Error('SC-11 VIOLATION: LLM_BASE_URL appears to be a public endpoint. Set it to a private/local host.');
}

// HIGH-03: Sanitize draft_text — strip common LLM injection delimiters
const safeDraft = String(audit.draft_text || '')
  .replace(/^(System:|SYSTEM:|###|\[INST\])/gm, '  ')
  .slice(0, 4000);

// MED-03: pass violation count only (not name strings) in system prompt
const violationCount = audit.violations.length;

const systemPrompt = [
  'You are a content safety editor. Rewrite the provided text to be 100% project-level with zero individual attribution.',
  '',
  'ABSOLUTE RULES:',
  '1. Never mention any person name, Discord handle, or numeric ID.',
  '2. Never attribute commits, hours, tasks, opinions, or blockers to any specific person.',
  '3. Use only feature-area or project-level framing:',
  '   Good: "The authentication feature has progressed this week."',
  '   Bad:  "Alice fixed the login bug and committed 12 times."',
  '4. Preserve all factual project-level information — only remove the individual layer.',
  '5. Return ONLY the rewritten text. No preamble, no explanation, no quotation marks.',
  '',
  violationCount + ' violation(s) detected — rewrite the text below to remove all individual attribution.'
].join('\n');

return [{ json: {
  model: $env.LLM_MODEL,
  temperature: 0.2,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: 'Rewrite to remove all individual attribution:\n\n' + safeDraft }
  ]
} }];

const response = $input.first().json;
const rewritten = String(response.choices?.[0]?.message?.content ?? '').trim();

if (!rewritten) {
  return [{ json: { clean: false, violations: ['Ollama returned empty response'], draft_text: '' } }];
}

const rosterRows = $('Fetch Roster').all();
const violations = [];

// MED-01: same normalization as Pattern Audit
const normalize = s => String(s).normalize('NFKD').replace(/[^\x00-\x7F]/g, '').toLowerCase();
const textNorm = normalize(rewritten);

const hasWordBoundary = (haystack, needle) => {
  let idx = 0;
  while ((idx = haystack.indexOf(needle, idx)) !== -1) {
    const pre  = idx === 0 || !/[a-z0-9]/.test(haystack[idx - 1]);
    const post = idx + needle.length >= haystack.length || !/[a-z0-9]/.test(haystack[idx + needle.length]);
    if (pre && post) return true;
    idx++;
  }
  return false;
};

for (const row of rosterRows) {
  const name = normalize(row.json.name || '');
  if (!name.trim()) continue;
  const parts = name.split(/\s+/).filter(p => p.length > 0);
  for (const part of parts) {
    if (hasWordBoundary(textNorm, part)) {
      violations.push('Name still present after rewrite: [REDACTED]');
      break;
    }
  }
}

const ids = rosterRows.map(r => String(r.json.discord_id || ''));
const digitsOnly = rewritten.replace(/\D/g, '');
const snowflakes = textNorm.match(/\b\d{17,19}\b/g) || [];
for (const id of ids) {
  if (!id) continue;
  if (snowflakes.includes(id) || (id.length >= 17 && digitsOnly.includes(id))) {
    violations.push('Discord ID still present after rewrite: [REDACTED]');
    break;
  }
}

// HIGH-01: full metric pattern set (same as Pattern Audit — catches Ollama hallucinations)
const metricPatterns = [
  [/\b\d+\s*commits?\b/i, 'commit count'],
  [/\b\d+\s*(hours?|hrs?)\s*(logged|tracked|worked)/i, 'individual hours'],
  [/logged\s+\d+\s*(hours?|hrs?)/i, 'individual hours (logged)'],
  [/\b(assigned to|done by|completed by|written by|handled by)\s+\w+/i, 'attribution phrase'],
  [/\b(he|she|they)\s+(committed|pushed|closed|opened|wrote|fixed|reviewed|built)\b/i, 'individual pronoun'],
];

for (const [re, label] of metricPatterns) {
  if (re.test(rewritten)) {
    violations.push('Pattern still present after rewrite: ' + label);
  }
}

return [{ json: {
  clean: violations.length === 0,
  violations,
  draft_text: rewritten
} }];
